-- CORREÇÃO DEFINITIVA DE PERFIS PHANTLAB (V2)
-- Execute este script no SQL Editor do Supabase para corrigir o erro "Database Error" no login

-- 1. Limpeza total de versões anteriores para evitar conflitos
DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
DROP FUNCTION IF EXISTS public.handle_new_user();

-- 2. Garantir que a tabela profiles existe e está correta
CREATE TABLE IF NOT EXISTS public.profiles (
  id uuid REFERENCES auth.users ON DELETE CASCADE NOT NULL PRIMARY KEY,
  full_name TEXT,
  avatar_url TEXT,
  role TEXT DEFAULT 'USER',
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now())
);

-- 3. Habilitar RLS (Segurança a nível de linha)
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;

-- 4. Criar políticas de acesso (caso não existam)
DO $$ 
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Public Profiles' AND tablename = 'profiles') THEN
        CREATE POLICY "Public Profiles" ON public.profiles FOR SELECT USING (true);
    END IF;

    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Own Profile Update' AND tablename = 'profiles') THEN
        CREATE POLICY "Own Profile Update" ON public.profiles FOR UPDATE USING (auth.uid() = id);
    END IF;

    -- Política para permitir inserção pelo próprio usuário (caso o trigger falhe e o front tente)
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE policyname = 'Enable insert for authenticated users only' AND tablename = 'profiles') THEN
        CREATE POLICY "Enable insert for authenticated users only" ON "public"."profiles" FOR INSERT WITH CHECK ((auth.uid() = id));
    END IF;
END $$;

-- 5. Função de Gatilho CORRIGIDA (SECURITY DEFINER é o segredo)
-- O 'SET search_path = public' é uma boa prática de segurança
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER SET search_path = public
AS $$
BEGIN
  INSERT INTO public.profiles (id, full_name, avatar_url, role)
  VALUES (
    new.id,
    COALESCE(new.raw_user_meta_data->>'full_name', new.raw_user_meta_data->>'name', 'Vendedor'),
    COALESCE(new.raw_user_meta_data->>'avatar_url', new.raw_user_meta_data->>'picture', ''),
    CASE 
      WHEN new.email = 'master@phantlab.com.br' THEN 'MASTER' 
      ELSE 'USER' 
    END
  )
  ON CONFLICT (id) DO UPDATE
  SET 
    full_name = EXCLUDED.full_name,
    avatar_url = EXCLUDED.avatar_url;

  RETURN new;
END;
$$;

-- 6. Recriar o Gatilho
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- 7. Permissões de schema e tabela (Garante que a API consiga ler/escrever)
GRANT USAGE ON SCHEMA public TO anon, authenticated, service_role;
GRANT ALL ON TABLE public.profiles TO postgres;
GRANT ALL ON TABLE public.profiles TO service_role;
GRANT SELECT, INSERT, UPDATE ON TABLE public.profiles TO anon, authenticated;

-- Confirmação visual
SELECT 'Correção aplicada com sucesso. Tente logar novamente.' as status;

-- ==============================================================================
-- CORREÇÃO DEFINITIVA DE SCHEMA E PERMISSÕES - PHANTLAB (V3)
-- ==============================================================================

-- 1. LIMPEZA DE GATILHOS ANTIGOS (Evita conflitos durante a migração)
DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
DROP FUNCTION IF EXISTS public.handle_new_user();

-- 2. GARANTIA DA TABELA DE PERFIS
-- Cria a tabela básica se não existir
CREATE TABLE IF NOT EXISTS public.profiles (
  id uuid REFERENCES auth.users ON DELETE CASCADE NOT NULL PRIMARY KEY,
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now())
);

-- 3. EVOLUÇÃO DE SCHEMA (MIGRAÇÃO)
-- Garante que as colunas existam, mesmo se a tabela já foi criada anteriormente
DO $$
BEGIN
    ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS full_name TEXT;
    ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS avatar_url TEXT;
    ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS role TEXT DEFAULT 'USER';
END $$;

-- 4. CONFIGURAÇÃO DE SEGURANÇA (RLS)
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;

-- Limpa políticas antigas para recriar corretamente
DROP POLICY IF EXISTS "Public profiles are viewable by everyone" ON public.profiles;
DROP POLICY IF EXISTS "Users can insert their own profile" ON public.profiles;
DROP POLICY IF EXISTS "Users can update own profile" ON public.profiles;
DROP POLICY IF EXISTS "Enable read access for all users" ON public.profiles;
DROP POLICY IF EXISTS "Enable insert for authenticated users only" ON public.profiles;

-- Cria políticas permissivas mas seguras
CREATE POLICY "Public profiles are viewable by everyone" 
ON public.profiles FOR SELECT 
USING (true);

CREATE POLICY "Users can insert their own profile" 
ON public.profiles FOR INSERT 
WITH CHECK (auth.uid() = id);

CREATE POLICY "Users can update own profile" 
ON public.profiles FOR UPDATE 
USING (auth.uid() = id);

-- 5. FUNÇÃO MESTRA COM PERMISSÃO ELEVADA (SECURITY DEFINER)
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER SET search_path = public
AS $$
BEGIN
  INSERT INTO public.profiles (id, full_name, avatar_url, role)
  VALUES (
    new.id,
    -- Tenta pegar o nome de várias fontes de metadados
    COALESCE(new.raw_user_meta_data->>'full_name', new.raw_user_meta_data->>'name', 'Vendedor'),
    -- Tenta pegar o avatar
    COALESCE(new.raw_user_meta_data->>'avatar_url', new.raw_user_meta_data->>'picture', ''),
    -- Define role baseado no email
    CASE 
      WHEN new.email = 'master@phantlab.com.br' THEN 'MASTER' 
      ELSE 'USER' 
    END
  )
  ON CONFLICT (id) DO UPDATE
  SET 
    full_name = EXCLUDED.full_name,
    avatar_url = EXCLUDED.avatar_url,
    updated_at = now();

  RETURN new;
END;
$$;

-- 6. RECRIA O GATILHO NO AUTH.USERS
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- 7. PERMISSÕES EXPLÍCITAS (GRANTS)
GRANT USAGE ON SCHEMA public TO anon, authenticated, service_role;
GRANT ALL ON TABLE public.profiles TO anon, authenticated, service_role;
GRANT ALL ON TABLE public.profiles TO postgres;

-- 8. BACKFILL (CORREÇÃO RETROATIVA)
-- Preenche perfis faltantes para usuários que já existem
INSERT INTO public.profiles (id, full_name, avatar_url, role)
SELECT 
    id,
    COALESCE(raw_user_meta_data->>'full_name', raw_user_meta_data->>'name', 'Vendedor'),
    COALESCE(raw_user_meta_data->>'avatar_url', raw_user_meta_data->>'picture', ''),
    CASE 
      WHEN email = 'master@phantlab.com.br' THEN 'MASTER' 
      ELSE 'USER' 
    END
FROM auth.users
WHERE id NOT IN (SELECT id FROM public.profiles)
ON CONFLICT (id) DO NOTHING;

-- Confirmação de execução
SELECT 'Schema atualizado (colunas adicionadas) e permissões corrigidas.' as status;

